import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../services/api';
import './AddCar.css';

const AddCar = () => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [uploadingImages, setUploadingImages] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    brand: '',
    model: '',
    year: new Date().getFullYear(),
    color: '',
    fuelType: 'Petrol',
    transmission: 'Manual',
    seatingCapacity: 5,
    mileage: '',
    rentPerDay: '',
    features: [],
    description: '',
  });
  const [images, setImages] = useState([]);
  const [imageUrls, setImageUrls] = useState([]);
  const [featureInput, setFeatureInput] = useState('');

  const fuelTypes = ['Petrol', 'Diesel', 'Electric', 'Hybrid', 'CNG'];
  const transmissionTypes = ['Manual', 'Automatic'];
  const seatingOptions = [2, 4, 5, 7, 8];

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value,
    });
  };

  const handleImageSelect = (e) => {
    const files = Array.from(e.target.files);
    if (files.length + images.length > 5) {
      toast.error('Maximum 5 images allowed');
      return;
    }
    setImages([...images, ...files]);
  };

  const removeImage = (index) => {
    const newImages = images.filter((_, i) => i !== index);
    setImages(newImages);
  };

  const uploadImages = async () => {
    if (images.length === 0) {
      toast.error('Please select at least one image');
      return false;
    }

    setUploadingImages(true);
    try {
      const formDataUpload = new FormData();
      images.forEach((image) => {
        formDataUpload.append('images', image);
      });

      const response = await api.post('/admin/upload/multiple', formDataUpload, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });

      const uploadedUrls = response.data.images.map((img) => img.url);
      setImageUrls(uploadedUrls);
      setUploadingImages(false);
      return uploadedUrls;
    } catch (error) {
      console.error('Image upload error:', error);
      toast.error(error.response?.data?.message || 'Failed to upload images');
      setUploadingImages(false);
      return false;
    }
  };

  const addFeature = () => {
    if (featureInput.trim()) {
      setFormData({
        ...formData,
        features: [...formData.features, featureInput.trim()],
      });
      setFeatureInput('');
    }
  };

  const removeFeature = (index) => {
    const newFeatures = formData.features.filter((_, i) => i !== index);
    setFormData({
      ...formData,
      features: newFeatures,
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    // Validate required fields
    if (!formData.name || !formData.brand || !formData.model || !formData.rentPerDay) {
      toast.error('Please fill in all required fields');
      return;
    }

    // Upload images first
    let uploadedUrls = imageUrls;
    if (images.length > 0 && imageUrls.length === 0) {
      uploadedUrls = await uploadImages();
      if (!uploadedUrls) return;
    }

    setLoading(true);
    try {
      const carData = {
        ...formData,
        images: uploadedUrls,
        year: parseInt(formData.year),
        seatingCapacity: parseInt(formData.seatingCapacity),
        mileage: formData.mileage ? parseInt(formData.mileage) : undefined,
        rentPerDay: parseFloat(formData.rentPerDay),
      };

      const response = await api.post('/cars', carData);

      if (response.data.success) {
        toast.success('Car added successfully!');
        navigate('/manage-cars');
      }
    } catch (error) {
      console.error('Add car error:', error);
      toast.error(error.response?.data?.message || 'Failed to add car');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="add-car-container">
      <div className="add-car-header">
        <h1>Add New Car</h1>
        <button className="btn-back" onClick={() => navigate('/manage-cars')}>
          ← Back to Cars
        </button>
      </div>

      <form onSubmit={handleSubmit} className="add-car-form">
        {/* Basic Information */}
        <div className="form-section">
          <h2>Basic Information</h2>
          <div className="form-row">
            <div className="form-group">
              <label>Car Name *</label>
              <input
                type="text"
                name="name"
                value={formData.name}
                onChange={handleInputChange}
                placeholder="e.g., Swift Dzire VXI"
                required
              />
            </div>
            <div className="form-group">
              <label>Brand *</label>
              <input
                type="text"
                name="brand"
                value={formData.brand}
                onChange={handleInputChange}
                placeholder="e.g., Maruti Suzuki"
                required
              />
            </div>
          </div>

          <div className="form-row">
            <div className="form-group">
              <label>Model *</label>
              <input
                type="text"
                name="model"
                value={formData.model}
                onChange={handleInputChange}
                placeholder="e.g., Dzire"
                required
              />
            </div>
            <div className="form-group">
              <label>Year *</label>
              <input
                type="number"
                name="year"
                value={formData.year}
                onChange={handleInputChange}
                min="2000"
                max={new Date().getFullYear() + 1}
                required
              />
            </div>
          </div>

          <div className="form-row">
            <div className="form-group">
              <label>Color</label>
              <input
                type="text"
                name="color"
                value={formData.color}
                onChange={handleInputChange}
                placeholder="e.g., White"
              />
            </div>
            <div className="form-group">
              <label>Mileage (km/l)</label>
              <input
                type="number"
                name="mileage"
                value={formData.mileage}
                onChange={handleInputChange}
                placeholder="e.g., 20"
                min="0"
              />
            </div>
          </div>
        </div>

        {/* Specifications */}
        <div className="form-section">
          <h2>Specifications</h2>
          <div className="form-row">
            <div className="form-group">
              <label>Fuel Type *</label>
              <select
                name="fuelType"
                value={formData.fuelType}
                onChange={handleInputChange}
                required
              >
                {fuelTypes.map((type) => (
                  <option key={type} value={type}>
                    {type}
                  </option>
                ))}
              </select>
            </div>
            <div className="form-group">
              <label>Transmission *</label>
              <select
                name="transmission"
                value={formData.transmission}
                onChange={handleInputChange}
                required
              >
                {transmissionTypes.map((type) => (
                  <option key={type} value={type}>
                    {type}
                  </option>
                ))}
              </select>
            </div>
          </div>

          <div className="form-row">
            <div className="form-group">
              <label>Seating Capacity *</label>
              <select
                name="seatingCapacity"
                value={formData.seatingCapacity}
                onChange={handleInputChange}
                required
              >
                {seatingOptions.map((seats) => (
                  <option key={seats} value={seats}>
                    {seats} Seater
                  </option>
                ))}
              </select>
            </div>
            <div className="form-group">
              <label>Rent Per Day (₹) *</label>
              <input
                type="number"
                name="rentPerDay"
                value={formData.rentPerDay}
                onChange={handleInputChange}
                placeholder="e.g., 2500"
                min="0"
                step="0.01"
                required
              />
            </div>
          </div>
        </div>

        {/* Features */}
        <div className="form-section">
          <h2>Features</h2>
          <div className="features-input-group">
            <input
              type="text"
              value={featureInput}
              onChange={(e) => setFeatureInput(e.target.value)}
              placeholder="Add a feature (e.g., AC, GPS)"
              onKeyPress={(e) => e.key === 'Enter' && (e.preventDefault(), addFeature())}
            />
            <button type="button" onClick={addFeature} className="btn-add-feature">
              Add Feature
            </button>
          </div>
          <div className="features-list">
            {formData.features.map((feature, index) => (
              <div key={index} className="feature-chip">
                {feature}
                <button
                  type="button"
                  onClick={() => removeFeature(index)}
                  className="btn-remove-feature"
                >
                  ×
                </button>
              </div>
            ))}
          </div>
        </div>

        {/* Description */}
        <div className="form-section">
          <h2>Description</h2>
          <textarea
            name="description"
            value={formData.description}
            onChange={handleInputChange}
            placeholder="Enter car description..."
            rows="4"
          />
        </div>

        {/* Images */}
        <div className="form-section">
          <h2>Images (Max 5) *</h2>
          <div className="image-upload-section">
            <input
              type="file"
              id="car-images"
              accept="image/*"
              multiple
              onChange={handleImageSelect}
              style={{ display: 'none' }}
            />
            <label htmlFor="car-images" className="btn-select-images">
              Select Images
            </label>
            {images.length > 0 && (
              <button
                type="button"
                onClick={() => uploadImages()}
                className="btn-upload-images"
                disabled={uploadingImages || imageUrls.length > 0}
              >
                {uploadingImages ? 'Uploading...' : imageUrls.length > 0 ? 'Uploaded ✓' : 'Upload Images'}
              </button>
            )}
          </div>

          <div className="images-preview">
            {images.map((image, index) => (
              <div key={index} className="image-preview-item">
                <img src={URL.createObjectURL(image)} alt={`Preview ${index + 1}`} />
                <button
                  type="button"
                  onClick={() => removeImage(index)}
                  className="btn-remove-image"
                  disabled={imageUrls.length > 0}
                >
                  ×
                </button>
              </div>
            ))}
          </div>
        </div>

        {/* Submit Button */}
        <div className="form-actions">
          <button
            type="button"
            onClick={() => navigate('/manage-cars')}
            className="btn-cancel"
            disabled={loading}
          >
            Cancel
          </button>
          <button
            type="submit"
            className="btn-submit"
            disabled={loading || uploadingImages || images.length === 0}
          >
            {loading ? 'Adding Car...' : 'Add Car'}
          </button>
        </div>
      </form>
    </div>
  );
};

export default AddCar;
